   317	            try self.sendTerminalProbeRsp(request.request_id, .timeout, &.{});
   318	        }
   319	        relay.reply_capture.clearRetainingCapacity();
   320	    }
   321	
   322	    fn matchingExpectedRequestIndex(relay: *const StartupRelay) ?usize {
   323	        for (relay.expected_requests.items, 0..) |request, idx| {
   324	            switch (startup_probe.classifyReply(request.kind, relay.reply_capture.items)) {
   325	                .complete => return idx,
   326	                .need_more => return null,
   327	                .invalid => {},
   328	            }
   329	        }
   330	        return null;
   331	    }
   332	
   333	    fn maybeFinishStartupRelay(self: *Client, relay: *StartupRelay, now_ns: u64) !void {
   334	        if (!relay.active) return;
   335	        if (now_ns - relay.started_at_ns >= relay_total_timeout_ns) {
   336	            try self.timeoutOutstandingProbes(relay);
   337	            try self.finishStartupRelay(relay);
   338	            return;
   339	        }
   340	        if (relay.expected_requests.items.len != 0 or relay.reply_capture.items.len != 0) return;
   341	        if (!relay.saw_probe_request and now_ns - relay.started_at_ns < relay_first_probe_grace_ns) return;
   342	
   343	        if (relay.hasBufferedNewline()) {
   344	            try self.finishStartupRelay(relay);
   345	            return;
   346	        }
   347	        if (now_ns - relay.last_probe_ns >= relay_quiescence_ns) {
   348	            try self.finishStartupRelay(relay);
   349	        }
   350	    }
   351	
   352	    fn routeStartupInput(self: *Client, relay: *StartupRelay, data: []const u8) !void {
   353	        var index: usize = 0;
   354	        while (index < data.len) : (index += 1) {
   355	            if (!relay.active) {
   356	                try self.sendKeyRaw(data[index..]);
   357	                return;
   358	            }
   359	
   360	            if (relay.expected_requests.items.len == 0 and relay.reply_capture.items.len == 0) {
   361	                try relay.buffered_user_input.appendSlice(self.allocator, data[index..]);
   362	                relay.last_probe_ns = monotonicNs();
   363	                return;
   364	            }
   365	
   366	            if (relay.reply_capture.items.len == 0 and data[index] != 0x1b) {
   367	                try relay.buffered_user_input.append(self.allocator, data[index]);
   368	                continue;
   369	            }
   370	
   371	            try relay.reply_capture.append(self.allocator, data[index]);
   372	            if (matchingExpectedRequestIndex(relay)) |request_idx| {
   373	                const request = relay.expected_requests.orderedRemove(request_idx);
   374	                var detail: [160]u8 = undefined;
   375	                const msg = std.fmt.bufPrint(&detail, "id={d} kind={s} bytes={d}", .{ request.request_id, @tagName(request.kind), relay.reply_capture.items.len }) catch "";
   376	                startup_probe.traceEvent("client", "matched_probe_reply", msg);
   377	                try self.sendTerminalProbeRsp(request.request_id, .complete, relay.reply_capture.items);
   378	                relay.reply_capture.clearRetainingCapacity();
   379	                relay.last_probe_ns = monotonicNs();
   380	                continue;
   381	            }
   382	
   383	            var needs_more = false;
   384	            for (relay.expected_requests.items) |request| {
   385	                if (startup_probe.classifyReply(request.kind, relay.reply_capture.items) == .need_more) {
   386	                    needs_more = true;
   387	                    break;
   388	                }
   389	            }
   390	            if (!needs_more) {
   391	                var detail: [160]u8 = undefined;
   392	                const msg = std.fmt.bufPrint(&detail, "bytes={d}", .{relay.reply_capture.items.len}) catch "";
   393	                startup_probe.traceEvent("client", "classify_non_probe_bytes", msg);
   394	                try relay.buffered_user_input.appendSlice(self.allocator, relay.reply_capture.items);
   395	                relay.reply_capture.clearRetainingCapacity();
   396	            }
   397	        }
   398	    }
   399	
   400	    fn startupRelayPollTimeout(relay: *const StartupRelay) c_int {
   401	        if (!relay.active) return -1;
   402	
   403	        const now_ns = monotonicNs();
   404	        var next_deadline = relay.started_at_ns + relay_total_timeout_ns;
   405	        if (relay.expected_requests.items.len == 0 and relay.reply_capture.items.len == 0) {
   406	            if (!relay.saw_probe_request) {
   407	                const first_probe_deadline = relay.started_at_ns + relay_first_probe_grace_ns;
   408	                if (first_probe_deadline < next_deadline) next_deadline = first_probe_deadline;
   409	            } else {
   410	                const quiescence_deadline = relay.last_probe_ns + relay_quiescence_ns;
   411	                if (quiescence_deadline < next_deadline) next_deadline = quiescence_deadline;
   412	            }
   413	        }
   414	
   415	        if (next_deadline <= now_ns) return 0;
   416	        const remaining_ns = next_deadline - now_ns;
   417	        const remaining_ms = remaining_ns / std.time.ns_per_ms;
   418	        return @intCast(@min(remaining_ms, @as(u64, @intCast(std.math.maxInt(c_int)))));
   419	    }
