   421	    /// Run an interactive session loop: relay stdin to server, server output to stdout.
   422	    /// Returns when the server sends detach, shutdown, or the connection drops.
   423	    pub fn interactiveLoop(self: *Client, existing_raw: ?*client_terminal.RawTerminal) !void {
   424	        // Get actual terminal size and notify server.
   425	        if (client_terminal.getTerminalSize(0)) |size| {
   426	            self.sendResize(size.cols, size.rows) catch {};
   427	        }
   428	
   429	        var owned_raw: ?client_terminal.RawTerminal = null;
   430	        var raw_ptr: *client_terminal.RawTerminal = undefined;
   440	        var relay = StartupRelay.init();
   441	        defer relay.deinit(self.allocator);
   442	        self.sendTerminalProbeReady() catch {
   443	            relay.active = false;
   444	        };
   445	
   446	        const POLLIN: i16 = 0x0001;
   447	        var pollfds = [_]std.c.pollfd{
   448	            .{ .fd = 0, .events = POLLIN, .revents = 0 },
   449	            .{ .fd = self.fd, .events = POLLIN, .revents = 0 },
   450	        };
   451	
   452	        while (true) {
   453	            const ret = std.c.poll(&pollfds, pollfds.len, startupRelayPollTimeout(&relay));
   454	            if (ret < 0) break;
   455	
   456	            const now_ns = monotonicNs();
   457	            if (now_ns - relay.started_at_ns >= relay_total_timeout_ns) {
   458	                self.timeoutOutstandingProbes(&relay) catch break;
   459	                self.finishStartupRelay(&relay) catch break;
   460	            }
   461	
   462	            // Server readable: handle messages.
   463	            if (pollfds[1].revents & POLLIN != 0) {
   464	                var msg = protocol.recvMessageAlloc(self.allocator, self.fd) catch break;
   465	                defer msg.deinit();
   466	
   467	                switch (msg.msg_type) {
   468	                    .output => {
   469	                        if (msg.payload.len > 0) {
   470	                            _ = std.c.write(1, msg.payload.ptr, msg.payload.len);
   471	                        }
   472	                    },
   473	                    .terminal_probe_req => {
   474	                        if (!relay.active) continue;
   475	                        const view = protocol.decodeTerminalProbeReq(msg.payload) catch continue;
   476	                        self.queueStartupProbe(&relay, view) catch break;
   477	                    },
   478	                    .detach, .shutdown, .exit_ack => break,
   479	                    else => {},
   480	                }
   481	            }
   482	
   483	            // stdin readable: forward to server as key data.
   484	            if (pollfds[0].revents & POLLIN != 0) {
   485	                var buf: [4096]u8 = undefined;
   486	                const n = std.c.read(0, &buf, buf.len);
   487	                if (n <= 0) break;
   488	                if (relay.active) {
   489	                    self.routeStartupInput(&relay, buf[0..@intCast(n)]) catch break;
   490	                } else {
   491	                    self.sendKeyRaw(buf[0..@intCast(n)]) catch break;
   492	                }
   493	            }
   494	
   495	            self.maybeFinishStartupRelay(&relay, monotonicNs()) catch break;
   496	        }
   497	    }
