   499	    /// Disconnect from the server.
   500	    pub fn disconnect(self: *Client) void {
   501	        if (self.fd >= 0) {
   502	            _ = std.c.close(self.fd);
   503	            self.fd = -1;
   504	        }
   505	    }
   506	
   507	    /// Check if connected.
   508	    pub fn isConnected(self: *const Client) bool {
   509	        return self.fd >= 0;
   510	    }
   511	};
